def is_nonstandard_cryptographic_algorithm(node):
    cryptographic_modules = ['cryptography.hazmat.primitives.asymmetric', 'cryptography.hazmat.primitives.ciphers']
    for module in cryptographic_modules:
        for node_ in node.get('children', []):
            if node_.get('name') == 'ImportFrom' and node_.get('module') == module:
                return True
    return False
